mapper.select:
SELECT r.id AS id, #{nodeName} as parentName, r.database_connect_id AS connectId, r.database_name AS dbName, r.schema_name AS schemaName, r.table_name AS tableName,
r.database_name AS name,
r.schema_name AS name,
r.table_name AS name,
r.column_name AS name,
r.resource_type AS type, c.db_type AS dbType, p.can_select, p.can_update, p.can_delete, p.can_insert, p.can_drop, p.can_merge, p.can_create, p.can_alter, p.can_create_index, p.can_drop_index, p.can_referenced, p.can_add, p.can_add_partition, p.can_analyze, p.allow FROM resource r left join permission p on p.resource_id = r.id and p.role_id = #{roleId} left join database_connect_config c on c.id = r.database_connect_id WHERE r.deleted = false AND r.resource_type =#{resourceType} and r.database_connect_id = #{connectId}
AND r.database_name = #{nodeName}
AND r.database_name = #{databaseName}
AND (r.database_name = #{nodeName} or r.schema_name = #{nodeName})
AND r.database_name = #{databaseName}
AND r.schema_name = #{schemaName}
AND r.table_name = #{nodeName} AND r.column_name != '*'

SELECT DISTINCT r.id AS id, r.database_connect_id AS connectId, r.database_name as dbName, r.schema_name as schemaName, #{nodeName} as parentName,
r.database_name AS name,
r.schema_name AS name,
r.table_name AS name,
r.column_name AS name,
r.resource_type AS type, c.db_type AS dbType FROM resource r left join database_connect_config c on c.id = r.database_connect_id WHERE r.deleted = false and r.database_connect_id = #{connectId} AND r.resource_type =#{resourceType}
AND r.database_name = #{dbName}
AND r.database_name = #{nodeName}
AND (r.database_name = #{nodeName} or r.schema_name = #{nodeName})
AND r.table_name = #{nodeName} AND r.column_name != '*'

choose.when:
select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'CONNECTION' where r1.id = #{id}
union all
select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'DATABASE' and r2.database_name = r1.database_name where r1.id = #{id}

select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'CONNECTION' where r1.id = #{id}
union all
select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'DATABASE' and r2.database_name = r1.database_name where r1.id = #{id}
union all
select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'SCHEMA' and r2.database_name = r1.database_name and (r2.schema_name IS NOT DISTINCT FROM r1.schema_name) where r1.id = #{id}

select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'CONNECTION' where r1.id = #{id}
union all
select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'DATABASE' and r2.database_name = r1.database_name where r1.id = #{id}
union all
select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'SCHEMA' and r2.database_name = r1.database_name and (r2.schema_name IS NOT DISTINCT FROM r1.schema_name) where r1.id = #{id}
union all
select r2.id from resource r1 inner join resource r2 on r2.database_connect_id = r1.database_connect_id and r2.deleted = false and r2.resource_type = 'TABLE' and r2.database_name = r1.database_name and (r2.schema_name IS NOT DISTINCT FROM r1.schema_name) and r2.table_name = r1.table_name where r1.id = #{id}
